import request from '@/utils/request'
import { SMS_SCENE } from '@/store'

export const auth = {
  // 密码登录
  async loginWithPassword(data) {
    try {
      const response = await request.post('/users/auth/login/password/', data)
      // 检查响应结构
      console.log('Login response:', response.data)

      if (response.data?.code === 200) {
        const { access, refresh } = response.data.data
        if (!access || !refresh) {
          throw new Error('登录响应中缺少必要的令牌信息')
        }
        return response
      }
      return response
    } catch (error) {
      console.error('Login error details:', error.response?.data)
      throw error
    }
  },

  // 退出登录
  logout: () => {
    const refreshToken = localStorage.getItem('refresh_token')
    if (!refreshToken) {
      return Promise.resolve()
    }

    return request({
      url: '/api/v1/users/auth/logout/',
      method: 'post',
      data: {
        refresh: refreshToken
      }
    }).catch(error => {
      if (error.response?.status === 401) {
        return Promise.resolve()
      }
      throw error
    })
  },

  // 刷新 token
  refreshToken: (data) => {
    return request({
      url: '/api/v1/users/auth/token/refresh/',
      method: 'post',
      data
    })
  },

  // 注册
  register: async (data) => {
    try {
      const response = await request({
        url: '/api/v1/users/auth/register/',
        method: 'post',
        data: {
          phone: data.phone,
          code: data.code,
          password: data.password,
          confirm_password: data.confirm_password
        }
      })

      if (!response.data || response.data.code !== 200) {
        throw new Error(response.data?.message || '注册失败')
      }

      // 保存 token
      if (response.data.data?.access) {
        localStorage.setItem('access_token', response.data.data.access)
      }
      if (response.data.data?.refresh) {
        localStorage.setItem('refresh_token', response.data.data.refresh)
      }

      return response
    } catch (error) {
      console.error('Register error:', error)
      if (error.response?.data?.message) {
        throw new Error(error.response.data.message)
      }
      throw error
    }
  },

  // 发送验证码
  sendVerifyCode: async (data) => {
    try {
      // 打印完整的请求数据
      console.log('Sending verify code request:', {
        url: '/api/v1/users/auth/sms/send/',
        method: 'post',
        data: {
          phone: data.phone.trim(),
          scene: data.scene
        }
      })

      const response = await request({
        url: '/api/v1/users/auth/sms/send/',
        method: 'post',
        headers: {
          'Content-Type': 'application/json'
        },
        data: {
          phone: data.phone.trim(),
          scene: data.scene
        }
      })

      // 检查响应格式
      if (!response.data || response.data.code !== 200) {
        throw new Error(response.data?.message || '发送验证码失败')
      }

      console.log('Send verify code response:', response)
      return response
    } catch (error) {
      // 打印详细的错误信息
      console.error('Send verify code error details:', {
        status: error.response?.status,
        data: error.response?.data,
        message: error.message,
        requestData: {
          phone: data.phone.trim(),
          scene: data.scene
        }
      })

      // 处理错误
      if (error.response?.data) {
        throw new Error(error.response.data.message || '发送验证码失败')
      }

      throw new Error(error.message || '发送验证码失败，请稍后重试')
    }
  },

  // 发送重置密码验证码
  sendResetCode: async (phone) => {
    try {
      const response = await request({
        url: '/api/v1/users/auth/sms/send/',
        method: 'post',
        data: {
          phone,
          scene: 'reset_password'
        }
      })

      if (!response.data || response.data.code !== 200) {
        throw new Error(response.data?.message || '发送验证码失败')
      }

      return response
    } catch (error) {
      console.error('Send reset code error details:', {
        status: error.response?.status,
        data: error.response?.data,
        message: error.message
      })

      if (error.response?.data) {
        const errorData = error.response.data

        // 处理具体的错误情况
        switch (errorData.code) {
          case 400:
            // 处理场景相关错误
            if (errorData.message?.includes('场景')) {
              throw new Error('无效的验证码场景')
            }
            // 处理手机号相关错误
            if (errorData.message?.includes('未注册')) {
              throw new Error('该手机号未注册，请先注册账号')
            }
            if (errorData.message?.includes('已注册')) {
              throw new Error('该手机号已注册，请直接登录')
            }
            if (errorData.message?.includes('已被使用')) {
              throw new Error('该手机号已被其他账号使用')
            }
            // 处理发送频率限制
            if (errorData.message?.includes('频繁')) {
              throw new Error('发送太频繁，请稍后再试')
            }
            break

          case 500:
            throw new Error('服务器繁忙，请稍后重试')
        }

        // 处理其他错误
        if (errorData.message) {
          throw new Error(errorData.message)
        }

        // 处理验证错误
        if (errorData.errors) {
          const errorMessages = []
          if (errorData.errors.phone) {
            errorMessages.push(errorData.errors.phone[0])
          }
          if (errorData.errors.scene) {
            errorMessages.push(errorData.errors.scene[0])
          }
          if (errorMessages.length > 0) {
            throw new Error(errorMessages.join('; '))
          }
        }
      }

      // 未知错误的通用提示
      throw new Error(error.message || '发送验证码失败，请稍后重试')
    }
  },

  // 重置密码
  resetPassword: async (data) => {
    try {
      const response = await request({
        url: '/api/v1/users/auth/password/reset/',
        method: 'post',
        data: {
          phone: data.phone,
          code: data.code,
          new_password: data.password,
          confirm_password: data.confirmPassword
        }
      })

      if (!response.data || response.data.code !== 200) {
        throw new Error(response.data?.message || '重置密码失败')
      }

      return response
    } catch (error) {
      // 打印错误信息以便调试
      console.error('Reset password error details:', {
        status: error.response?.status,
        data: error.response?.data,
        message: error.message
      })

      // 处理错误信息
      if (error.response?.data) {
        const errorData = error.response.data

        // 处理验证错误
        if (errorData.errors) {
          const errorMessages = []
          if (errorData.errors.phone) {
            errorMessages.push(errorData.errors.phone[0])
          }
          if (errorData.errors.code) {
            errorMessages.push(errorData.errors.code[0])
          }
          if (errorData.errors.new_password) {
            errorMessages.push(errorData.errors.new_password[0])
          }
          if (errorData.errors.confirm_password) {
            errorMessages.push(errorData.errors.confirm_password[0])
          }
          if (errorMessages.length > 0) {
            throw new Error(errorMessages.join('; '))
          }
        }

        // 处理一般错误消息
        if (errorData.message) {
          throw new Error(errorData.message)
        }
      }

      // 如果没有具体错误信息，则抛出通用错误
      throw new Error(error.message || '重置密码失败，请稍后重试')
    }
  },

  // 更换手机号
  changePhone: async (data) => {
    const token = localStorage.getItem('access_token')
    if (!token) {
      throw new Error('未登录或登录已过期')
    }

    try {
      const response = await request({
        url: '/api/v1/users/account/phone/',
        method: 'post',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        data: {
          phone: data.phone,
