        return null
      }
      const response = await request.get('/users/info/')
      return response
    } catch (error) {
      console.error('Get user info error:', error)
      throw error
    }
  },

  // 上传头像
  uploadAvatar: async (formData) => {
    try {
      const response = await request({
        url: '/api/v1/users/profile/avatar/upload/',
        method: 'post',
        headers: {
          'Content-Type': 'multipart/form-data'
        },
        data: formData
      })

      return response
    } catch (error) {
      throw error
    }
  },

  // 更新用户名
  updateUsername: async (data) => {
    try {
      const response = await request({
        url: '/api/v1/users/account/username/',
        method: 'post',
        data: {
          username: data.username
        }
      })

      if (!response.data || response.data.code !== 200) {
        const error = new Error()
        error.message = {
          message: response.data?.message || '更新昵称失败',
          type: 'error'
        }
        throw error
      }

      return response
    } catch (error) {
      console.error('Update username error:', error)
      // 处理特定的错误情况
      if (error.response?.status === 500) {
        const customError = new Error()
        customError.message = {
          message: '该昵称已被使用，请更换其他昵称',
          type: 'warning'
        }
        throw customError
      }
      // 处理其他错误情况
      if (error.response?.data?.message) {
        const customError = new Error()
        customError.message = {
          message: error.response.data.message,
          type: 'error'
        }
        throw customError
      }
      const defaultError = new Error()
      defaultError.message = {
        message: '更新昵称失败，请稍后重试',
        type: 'error'
      }
      throw defaultError
    }
  },

  // 更新基本信息
  updateBasicInfo: async (data) => {
    try {
      const response = await request({
        url: '/api/v1/users/profile/basic/',
        method: 'post',
        data: {
          basic_info: {
            ...data
          }
        }
      })

      return response
    } catch (error) {
      throw error
    }
  },

  // 删除账户
  deleteAccount: async (data) => {
    try {
      const response = await request({
        url: '/api/v1/users/account/delete/',
        method: 'post',
        data: {
          password: data.password
        }
      })

      if (!response.data || response.data.code !== 200) {
        throw new Error(response.data?.message || '注销账户失败')
      }

      return response
    } catch (error) {
      console.error('Delete account error:', error.response || error)
      if (error.response?.data?.message) {
        throw new Error(error.response.data.message)
      }
      throw error
    }
  },

  // 修改密码
  updatePassword: async (data) => {
    try {
      const response = await request({
        url: '/api/v1/users/account/password/',
        method: 'post',
        data: {
          old_password: data.old_password,
          new_password: data.new_password,
          confirm_password: data.confirm_password
        }
      })

      if (!response.data || response.data.code !== 200) {
        throw new Error(response.data?.message || '修改密码失败')
      }

      return response
    } catch (error) {
      throw error
    }
  }
}
